:host {
  display: flex;
  flex-direction: column;
  box-sizing: border-box;
  width: var(--_card-width);
  min-height: var(--_card-min-height);
  max-width: 100%;
  border: none;
  border-radius: var(--dimension-radius-025);
  background-color: var(--color-background-primary);
  box-shadow: 0 0 0 var(--dimension-stroke-width-012) var(--color-border-tertiary);
  overflow: hidden;
}

:host(.card--editing) {
  background-color: var(--color-background-bold-brand);
  box-shadow: 0 0 0 var(--dimension-stroke-width-025) var(--color-border-bold-brand);
}

.card__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--dimension-space-100);
  height: var(--dimension-size-600);
  flex-shrink: 0;
  padding: var(--dimension-space-100);
  background-color: var(--color-background-secondary);
  border-bottom: var(--dimension-stroke-width-012) solid var(--color-border-tertiary);
  box-sizing: border-box;
}

:host(.card--editing) .card__header {
  background-color: transparent;
  border-bottom-color: transparent;
}

.card__title-wrap {
  flex: 1 1 auto;
  min-width: 0;
  display: flex;
  align-items: center;
  padding: var(--dimension-space-075);
  box-sizing: border-box;
  -webkit-user-select: none;
  user-select: none;
}

.card__title {
  display: inline-flex;
  align-items: center;
  min-width: 0;
  padding: var(--dimension-space-025);
}

.card__actions {
  display: flex;
  flex-shrink: 0;
  align-items: center;
  gap: var(--dimension-space-100);
}

.card__actions:empty {
  display: none;
}

.card__body {
  flex: 1 1 auto;
  min-height: 0;
  display: flex;
  flex-direction: column;
  border-radius: 0 0 var(--dimension-radius-025) var(--dimension-radius-025);
  background-color: var(--color-background-primary);
  box-sizing: border-box;
}

:host(.card--editing) .card__body {
  border-radius: var(--dimension-radius-025);
}

import { Component, h, Host, Prop } from '@stencil/core';

export type CardWidth = 'sm' | 'md' | 'lg';

/** Visual chrome recipe — default app surface, or settings edit wash. */
export type CardAppearance = 'default' | 'editing';

const CARD_WIDTH_VARS: Record<CardWidth, string> = {
  sm: 'var(--dimension-card-width-sm)',
  md: 'var(--dimension-card-width-md)',
  lg: 'var(--dimension-card-width-lg)',
};

const CARD_HEIGHT_VARS: Record<CardWidth, string> = {
  sm: 'var(--dimension-card-height-sm)',
  md: 'var(--dimension-card-height-md)',
  lg: 'var(--dimension-card-height-lg)',
};

const FAINT_BRAND_TITLE_COLOR = 'var(--color-foreground-faint-brand)';

/**
 * Shared card chrome — width + matching min-height tokens, header (title + actions),
 * and a flex body that fills leftover space. Compose this from settings / data-viz cards.
 */
@Component({
  tag: 'ds-card',
  styleUrl: 'Card.css',
  scoped: true,
})
export class Card {
  /** Section heading shown in the card header. */
  @Prop() heading!: string;

  /**
   * Card width token (`sm` / `md` / `lg`). Also sets host `min-height` to the
   * matching `--dimension-card-height-*` so empty bodies still fill the card.
   */
  @Prop() cardWidth: CardWidth = 'md';

  /** Chrome recipe — `editing` applies the settings edit wash. */
  @Prop() appearance: CardAppearance = 'default';

  render() {
    const editing = this.appearance === 'editing';

    return (
      <Host
        class={{
          card: true,
          'card--editing': editing,
        }}
        style={{
          '--_card-width': CARD_WIDTH_VARS[this.cardWidth],
          '--_card-min-height': CARD_HEIGHT_VARS[this.cardWidth],
        }}
      >
        <header class="card__header">
          <div class="card__title-wrap">
            <ds-text
              class="card__title"
              variant="text-title-small"
              color={editing ? FAINT_BRAND_TITLE_COLOR : 'primary'}
              as="h2"
            >
              {this.heading}
            </ds-text>
          </div>
          <div class="card__actions">
            <slot name="actions" />
          </div>
        </header>
        <div class="card__body">
          <slot />
        </div>
      </Host>
    );
  }
}
